questionvariables.text:
/* Class width */
w:10;

/* Random starting point */
start: rand(5)*5;   /* e.g. 0,5,10,15,20 */

/* Class intervals */
c1l:start;        c1u:start+w;
c2l:c1u;          c2u:c2l+w;
c3l:c2u;          c3u:c3l+w;
c4l:c3u;          c4u:c4l+w;
c5l:c4u;          c5u:c5l+w;

/* Frequencies */
f1: rand(8)+2;
f2: rand(8)+2;
f3: rand(8)+2;
f4: rand(8)+2;
f5: rand(8)+2;

/* Midpoints */
m1:(c1l+c1u)/2;
m2:(c2l+c2u)/2;
m3:(c3l+c3u)/2;
m4:(c4l+c4u)/2;
m5:(c5l+c5u)/2;

/* Correct midpoint list */
ta_mid:[m1,m2,m3,m4,m5];

/* Frequency polygon coordinates */
ta_poly:[[m1,f1],[m2,f2],[m3,f3],[m4,f4],[m5,f5]];
